    /// <summary>
    /// Retrieves the icon entry for the specified icon name and variant.
    /// </summary>
    public static FontAwesomeIconEntry? GetIcon(string name, FontAwesomeIconVariant variant)
    {
        var dictionary = variant switch
        {
            FontAwesomeIconVariant.Solid => SolidIcons,
            FontAwesomeIconVariant.Regular => RegularIcons,
            FontAwesomeIconVariant.Brands => BrandsIcons,
            _ => SolidIcons
        };

        return dictionary.TryGetValue(name, out var entry) ? entry : null;
    }

    /// <summary>
    /// Gets all available icon names for a specific variant.
    /// </summary>
    public static IEnumerable<string> GetAvailableIcons(FontAwesomeIconVariant variant)
    {
        return variant switch
        {
            FontAwesomeIconVariant.Solid => SolidIcons.Keys,
            FontAwesomeIconVariant.Regular => RegularIcons.Keys,
            FontAwesomeIconVariant.Brands => BrandsIcons.Keys,
            _ => SolidIcons.Keys
        };
    }

    /// <summary>
    /// Checks whether an icon with the specified name exists in the given variant.
    /// </summary>
    public static bool IconExists(string name, FontAwesomeIconVariant variant)
    {
        return variant switch
        {
            FontAwesomeIconVariant.Solid => SolidIcons.ContainsKey(name),
            FontAwesomeIconVariant.Regular => RegularIcons.ContainsKey(name),
            FontAwesomeIconVariant.Brands => BrandsIcons.ContainsKey(name),
            _ => SolidIcons.ContainsKey(name)
        };
    }

    /// <summary>
    /// Gets the total number of available icons across all variants.
    /// </summary>
    public static int TotalIconCount => SolidIcons.Count + RegularIcons.Count + BrandsIcons.Count;

    /// <summary>
    /// Gets the number of Solid icons.
    /// </summary>
    public static int SolidIconCount => SolidIcons.Count;

    /// <summary>
    /// Gets the number of Regular icons.
    /// </summary>
    public static int RegularIconCount => RegularIcons.Count;

    /// <summary>
    /// Gets the number of Brands icons.
    /// </summary>
    public static int BrandsIconCount => BrandsIcons.Count;
}
